class ThemeToggle{constructor(){this.isDark=false;this.init();}init(){this.loadTheme();this.createToggle();this.bindEvents();this.setupSystemPreferenceListener();}loadTheme(){const stored=localStorage.getItem('sadec-theme');if(stored){this.isDark=stored==='dark';}else{this.isDark=window.matchMedia('(prefers-color-scheme: dark)').matches;}this.applyTheme();}applyTheme(){if(this.isDark){document.documentElement.setAttribute('data-theme','dark');document.documentElement.classList.add('dark-mode');}else{document.documentElement.removeAttribute('data-theme');document.documentElement.classList.remove('dark-mode');}}createToggle(){const header=document.querySelector('.header-section')||document.querySelector('header')||document.querySelector('.toolbar-left');if(!header)return;const toggle=document.createElement('button');toggle.id='theme-toggle';toggle.className='theme-toggle';toggle.setAttribute('aria-label','Toggle dark mode');toggle.setAttribute('title','Chuyển chế độ sáng/tối');toggle.innerHTML=`<span class="material-symbols-outlined theme-icon-light">light_mode</span><span class="material-symbols-outlined theme-icon-dark" style="display: none;">dark_mode</span>`;const searchGlass=header.querySelector('.search-glass');if(searchGlass){searchGlass.after(toggle);}else{header.appendChild(toggle);}this.toggleEl=toggle;this.updateIcon();}updateIcon(){if(!this.toggleEl)return;const lightIcon=this.toggleEl.querySelector('.theme-icon-light');const darkIcon=this.toggleEl.querySelector('.theme-icon-dark');if(this.isDark){lightIcon.style.display='none';darkIcon.style.display='inline';}else{lightIcon.style.display='inline';darkIcon.style.display='none';}}bindEvents(){if(this.toggleEl){this.toggleEl.addEventListener('click',()=>{this.toggle();});}document.addEventListener('keydown',(e)=>{if(e.ctrlKey&&e.shiftKey&&e.key==='D'){e.preventDefault();this.toggle();}});}setupSystemPreferenceListener(){const mediaQuery=window.matchMedia('(prefers-color-scheme: dark)');const handleChange=(e)=>{if(!localStorage.getItem('sadec-theme')){this.isDark=e.matches;this.applyTheme();this.updateIcon();}};mediaQuery.addEventListener('change',handleChange);}toggle(){this.isDark=!this.isDark;this.applyTheme();this.updateIcon();localStorage.setItem('sadec-theme',this.isDark ? 'dark' : 'light');this.announceChange();}announceChange(){const message=this.isDark ? 'Đã bật chế độ tối' : 'Đã tắt chế độ tối';const announcement=document.createElement('div');announcement.className='sr-only';announcement.setAttribute('aria-live','polite');announcement.textContent=message;document.body.appendChild(announcement);setTimeout(()=>announcement.remove(),1000);}setTheme(theme){this.isDark=theme==='dark';this.applyTheme();this.updateIcon();localStorage.setItem('sadec-theme',theme);}getTheme(){return this.isDark ? 'dark' : 'light';}}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>{window.themeToggle=new ThemeToggle();});}else{window.themeToggle=new ThemeToggle();}export{ThemeToggle};